using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

internal static class TestDbContextFactory
{
    public static SchoolContext Create(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(dbName)
            .Options;

        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    public static SchoolContext CreateSeeded(string? dbName = null)
    {
        var context = Create(dbName);
        SeedData(context);
        return context;
    }

    private static void SeedData(SchoolContext context)
    {
        var instructors = new[]
        {
            new Instructor { ID = 1, LastName = "Abercrombie", FirstMidName = "Kim", HireDate = DateTime.Parse("1995-03-11") },
            new Instructor { ID = 2, LastName = "Fakhouri", FirstMidName = "Fadi", HireDate = DateTime.Parse("2002-07-06") },
            new Instructor { ID = 3, LastName = "Harui", FirstMidName = "Roger", HireDate = DateTime.Parse("1998-07-01") }
        };
        context.Instructors.AddRange(instructors);

        var departments = new[]
        {
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2 },
            new Department { DepartmentID = 3, Name = "Engineering", Budget = 200000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 3 }
        };
        context.Departments.AddRange(departments);

        var courses = new[]
        {
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 },
            new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 2 },
            new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = 1 }
        };
        context.Courses.AddRange(courses);

        var students = new[]
        {
            new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { ID = 3, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2013-09-01") }
        };
        context.Students.AddRange(students);

        var enrollments = new[]
        {
            new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, StudentID = 1, CourseID = 4022, Grade = Grade.C },
            new Enrollment { EnrollmentID = 3, StudentID = 2, CourseID = 4041, Grade = Grade.B }
        };
        context.Enrollments.AddRange(enrollments);

        context.SaveChanges();
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student 'Test Student' has been created")]
    [DataRow(EntityOperation.UPDATE, "Student 'Test Student' has been updated")]
    [DataRow(EntityOperation.DELETE, "Student 'Test Student' has been deleted")]
    public void SendNotification_WithDisplayName_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
    {
        // Arrange
        using var service = new NotificationService();
        DrainQueue(service);

        // Act
        service.SendNotification("Student", "1", "Test Student", operation, "Admin");

        // Assert
        var notification = service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Course (ID: 101) has been created")]
    [DataRow(EntityOperation.UPDATE, "Course (ID: 101) has been updated")]
    [DataRow(EntityOperation.DELETE, "Course (ID: 101) has been deleted")]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage(EntityOperation operation, string expectedMessage)
    {
        // Arrange
        using var service = new NotificationService();
        DrainQueue(service);

        // Act
        service.SendNotification("Course", "101", operation, "Admin");

        // Assert
        var notification = service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    public void SendNotification_SetsAllProperties()
    {
        // Arrange
        using var service = new NotificationService();
        DrainQueue(service);

        // Act
        service.SendNotification("Department", "5", "Science", EntityOperation.CREATE, "TestUser");

        // Assert
        var notification = service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department", notification.EntityType);
        Assert.AreEqual("5", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("TestUser", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsTrue(notification.CreatedAt <= DateTime.Now);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Arrange
        using var service = new NotificationService();
        DrainQueue(service);

        // Act
        service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

        // Assert
        var notification = service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Arrange
        using var service = new NotificationService();
        DrainQueue(service);

        // Act
        var result = service.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        using var service = new NotificationService();
        DrainQueue(service);

        service.SendNotification("A", "1", "First", EntityOperation.CREATE);
        service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

        // Act & Assert
        var first = service.ReceiveNotification();
        var second = service.ReceiveNotification();

        Assert.IsNotNull(first);
        Assert.IsNotNull(second);
        Assert.AreEqual("A", first.EntityType);
        Assert.AreEqual("B", second.EntityType);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Arrange
        using var service = new NotificationService();

        // Act & Assert - MarkAsRead is a no-op but should not throw
        service.MarkAsRead(1);
        service.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        // Arrange
        var service = new NotificationService();

        // Act & Assert - Should not throw
        service.Dispose();
        service.Dispose();
    }

    private static void DrainQueue(NotificationService service)
    {
        while (service.ReceiveNotification() != null) { }
    }
}

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
    }

    [TestMethod]
    public void Create_CalculatesTotalPagesCorrectly()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    [DataRow(1, false, true)]
    [DataRow(2, true, true)]
    [DataRow(3, true, false)]
    public void HasPreviousPage_And_HasNextPage_AreCorrect(int pageIndex, bool expectedHasPrev, bool expectedHasNext)
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex, pageSize: 10);

        // Assert
        Assert.AreEqual(expectedHasPrev, result.HasPreviousPage);
        Assert.AreEqual(expectedHasNext, result.HasNextPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_ExactPageSize_HasSinglePage()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<string>(new List<string> { "a", "b" }, count: 20, pageIndex: 2, pageSize: 5);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
        Assert.AreEqual(4, list.TotalPages);
    }
}

