using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _controller = new StudentsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_NoParameters_ReturnsViewWithStudents()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudents()
    {
        // Act
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersCorrectly()
    {
        // Act
        var result = _controller.Index(null, null, "Meredith", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alonso", model[0].LastName);
    }

    [TestMethod]
    [DataRow("name_desc", "Anand")]
    [DataRow("", "Alexander")]
    [DataRow(null, "Alexander")]
    public void Index_SortOrder_SortsByLastName(string? sortOrder, string expectedFirstLastName)
    {
        // Act
        var result = _controller.Index(sortOrder, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(expectedFirstLastName, model[0].LastName);
    }

    [TestMethod]
    public void Index_SortByDate_OrdersByEnrollmentDate()
    {
        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // Earliest date first
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SortByDateDesc_OrdersByEnrollmentDateDescending()
    {
        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // Latest date first
        Assert.AreEqual("Anand", model[0].LastName);
    }

    [TestMethod]
    public void Index_NewSearchString_ResetsPageToOne()
    {
        // Act
        var result = _controller.Index(null, null, "A", 5) as ViewResult;

        // Assert - when searchString is not null, page is reset to 1
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        // Act
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsStudentWithEnrollments()
    {
        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
        Assert.AreEqual(2, student.Enrollments.Count);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual(DateTime.Today, student.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            LastName = "New",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        // Act
        var result = _controller.Create(student) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(4, _context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidEnrollmentDate_ReturnsView()
    {
        // Arrange
        var student = new Student
        {
            LastName = "New",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(student, result.Model);
    }

    [TestMethod]
    public void Create_Post_DateBelow1753_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Edit(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
    }

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit((int?)null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NonExistentId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = _context.Students.First();
        student.LastName = "Updated";

        // Detach to simulate form binding
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        // Act
        var result = _controller.Edit(student) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidEnrollmentDate_ReturnsView()
    {
        // Arrange
        var student = new Student
        {
            ID = 1,
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Edit(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(student, result.Model);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
    }

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_NonExistentId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        // Act
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
