        Assert.IsNotNull(json);
        // Use reflection to check dynamic properties
        var successProp = json.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(json));

        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(json));
    }

