using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context = null!;
    private CoursesController _controller = null!;
    private Mock<IWebHostEnvironment> _envMock = null!;
    private Mock<ILogger<CoursesController>> _loggerMock = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewWithAllCourses()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(4, model.Count);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        // Act
        var result = _controller.Details(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Create_Get_ReturnsViewWithEmptyCourse()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
    }

    [TestMethod]
    public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 4,
            DepartmentID = 1
        };

        // Act
        var result = _controller.Create(course, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(5, _context.Courses.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        var course = new Course { CourseID = 5555, Title = "X", Credits = 0, DepartmentID = 1 };
        _controller.ModelState.AddModelError("Title", "Too short");

        // Act
        var result = _controller.Create(course, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(course, result.Model);
    }

    [TestMethod]
    public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        // Arrange
        var course = new Course { CourseID = 7777, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = CreateMockFile("test.exe", 1024);

        // Act
        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Create_Post_FileTooLarge_ReturnsViewWithError()
    {
        // Arrange
        var course = new Course { CourseID = 7777, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = CreateMockFile("test.jpg", 6 * 1024 * 1024); // 6MB

        // Act
        var result = _controller.Create(course, fileMock.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Create_Post_ValidImage_SavesFileAndRedirects()
    {
        // Arrange
        var course = new Course { CourseID = 8888, Title = "Image Course", Credits = 3, DepartmentID = 1 };
        var fileMock = CreateMockFile("photo.png", 1024);

        // Act
        var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        var saved = _context.Courses.Find(8888);
        Assert.IsNotNull(saved);
        Assert.IsTrue(saved.TeachingMaterialImagePath!.StartsWith("/Uploads/TeachingMaterials/"));
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithCourse()
    {
        // Act
        var result = _controller.Edit(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
    }

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NonExistentId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(9999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        // Arrange
        var course = _context.Courses.First();
        course.Title = "Updated Chemistry";
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        // Act
        var result = _controller.Edit(course, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        var course = new Course { CourseID = 1050, Title = "X", Credits = 0, DepartmentID = 1 };
        _controller.ModelState.AddModelError("Credits", "Invalid");

        // Act
        var result = _controller.Edit(course, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
    {
        // Arrange
        var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
        _context.Entry(_context.Courses.Find(1050)!).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
        var fileMock = CreateMockFile("doc.pdf", 1024);

        // Act
        var result = _controller.Edit(course, fileMock.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithCourse()
    {
        // Act
        var result = _controller.Delete(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
    }

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
    {
        // Act
        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(3, _context.Courses.Count());
    }

    private static Mock<IFormFile> CreateMockFile(string fileName, long length)
    {
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns(fileName);
        fileMock.Setup(f => f.Length).Returns(length);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())); // No-op
        return fileMock;
    }
}

