using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();

        // Add course assignments for testing
        _context.CourseAssignments.AddRange(
            new CourseAssignment { InstructorID = 1, CourseID = 1050 },
            new CourseAssignment { InstructorID = 1, CourseID = 4022 }
        );
        _context.SaveChanges();

        _controller = new InstructorsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_NoParameters_ReturnsViewWithInstructors()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        // Act
        var result = _controller.Index(1, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(2, model.Courses.Count());
    }

    [TestMethod]
    public void Index_WithCourseId_PopulatesEnrollments()
    {
        // Arrange - add enrollment for course 1050
        _context.Enrollments.Add(new Enrollment { StudentID = 1, CourseID = 1050, Grade = Grade.A });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(1, 1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Enrollments);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.IsNotNull(instructor);
        Assert.AreEqual("Abercrombie", instructor.LastName);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_NonExistentId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Get_ReturnsView()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = DateTime.Parse("2020-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null!) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(4, _context.Instructors.Count());
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "CourseInstructor",
            FirstMidName = "Test",
            HireDate = DateTime.Parse("2020-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };
        var selectedCourses = new[] { "1050", "4022" };

        // Act
        var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "Test",
            FirstMidName = "User",
            HireDate = DateTime.Now,
            CourseAssignments = new List<CourseAssignment>()
        };
        _controller.ModelState.AddModelError("HireDate", "Invalid");

        // Act
        var result = _controller.Create(instructor, null!) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.IsNotNull(instructor);
        Assert.AreEqual("Abercrombie", instructor.LastName);
    }

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_NonExistentId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
    {
        // Arrange - add office assignment to test cascade behavior
        _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 2, Location = "Room 101" });
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(2) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(2, _context.Instructors.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorWithDepartment_NullsDepartmentAdmin()
    {
        // Instructor 1 is admin of department 1
        // Act
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        var dept = _context.Departments.Find(1);
        Assert.IsNotNull(dept);
        Assert.IsNull(dept.InstructorID);
    }
}

