using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context = null!;
    private HomeController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _controller = new HomeController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void About_ReturnsViewWithEnrollmentGroups()
    {
        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        // We have 3 students with 3 different enrollment dates
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void About_GroupsStudentsByEnrollmentDate()
    {
        // Arrange - add a student with same date as existing
        _context.Students.Add(new Student
        {
            LastName = "Same",
            FirstMidName = "Date",
            EnrollmentDate = DateTime.Parse("2010-09-01") // same as Alexander
        });
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count); // Still 3 groups
        var group2010 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2010-09-01"));
        Assert.AreEqual(2, group2010.StudentCount);
    }

    [TestMethod]
    public void Contact_ReturnsViewWithMessage()
    {
        // Act
        var result = _controller.Contact() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsView()
    {
        // Act
        var result = _controller.Error() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsViewWithMessage()
    {
        // Act
        var result = _controller.Unauthorized() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }
}

