using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _controller = new NotificationsController(_context);
        _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));

        // Drain any pre-existing notifications from the static queue
        using var drainService = new NotificationService();
        while (drainService.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        // Use reflection to check dynamic properties
        var successProp = json.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(json));

        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(json));
    }

    [TestMethod]
    public void GetNotifications_WithMessages_ReturnsNotifications()
    {
        // Arrange - Add notifications via the service
        using var service = new NotificationService();
        service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
        service.SendNotification("Course", "2", "Math", EntityOperation.UPDATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(2, countProp.GetValue(json));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange - Add more than 10 notifications
        using var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), $"Item {i}", EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(10, countProp.GetValue(json));
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var successProp = json.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(json));
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }
}

