[TestMethod]
public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
{
    // Arrange
    using var service = new NotificationService();
    // Drain pre-existing
    while (service.ReceiveNotification() != null) { }

    // Use unique entity IDs to avoid collision with other tests
    service.SendNotification("FifoA", "881", "First", EntityOperation.CREATE);
    service.SendNotification("FifoB", "882", "Second", EntityOperation.UPDATE);

    // Act & Assert - FifoA should come before FifoB since it was enqueued first
    var first = DrainUntilMatch(service, "FifoA", "881", "CREATE");
    var second = DrainUntilMatch(service, "FifoB", "882", "UPDATE");

    Assert.IsNotNull(first);
    Assert.IsNotNull(second);
    Assert.AreEqual("FifoA", first.EntityType);
    Assert.AreEqual("FifoB", second.EntityType);
}

