arguments.new_str:
[TestMethod]
public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
{
    // Arrange - use a unique prefix so we can identify our messages
    using var service = new NotificationService();

    var uniqueId = Guid.NewGuid().ToString("N")[..8];
    service.SendNotification($"FIFO_{uniqueId}", "1", "First", EntityOperation.CREATE);
    service.SendNotification($"FIFO_{uniqueId}", "2", "Second", EntityOperation.UPDATE);

    // Act - collect our messages in order
    var ours = new List<Notification>();
    for (int i = 0; i < 200 && ours.Count < 2; i++)
    {
        var n = service.ReceiveNotification();
        if (n == null) break;
        if (n.EntityType == $"FIFO_{uniqueId}")
            ours.Add(n);
    }

    // Assert
    Assert.AreEqual(2, ours.Count);
    Assert.AreEqual("1", ours[0].EntityId); // First sent, first received
    Assert.AreEqual("2", ours[1].EntityId);
}

