using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded();
        _controller = new NotificationsController(_context);
        ControllerTestHelper.SetupController(_controller);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void GetNotifications_ReturnsJsonWithSuccessTrue()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var successProp = json.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(json));
    }

    [TestMethod]
    public void GetNotifications_ReturnsCountProperty()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        var count = (int)countProp.GetValue(json)!;
        Assert.IsTrue(count >= 0 && count <= 10);
    }

    [TestMethod]
    public void GetNotifications_NeverReturnsMoreThan10()
    {
        // Arrange - Add many notifications
        using var service = new NotificationService();
        for (int i = 0; i < 20; i++)
        {
            service.SendNotification("Bulk", i.ToString(), $"Item {i}", EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var countProp = json.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        var count = (int)countProp.GetValue(json)!;
        Assert.IsTrue(count <= 10, $"Expected at most 10, got {count}");
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var json = result.Value;
        Assert.IsNotNull(json);
        var successProp = json.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(json));
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }
}

